import React, { useState } from 'react';
import { SearchProductCard as DefaultSearchProductCard } from './SearchProductCard.js';
import type { SearchProductCardProps } from './SearchProductCard.js';
import { SearchBlogCard as DefaultSearchBlogCard } from './SearchBlogCard.js';
import type { SearchBlogCardProps } from './SearchBlogCard.js';
import { buildSafeUrl, safeNavigate } from '../../utils/index.js';
import { useComponent } from '../../hooks/useComponent.js';

const CATEGORIES_FIRST_ROW = 3;
const PRODUCTS_FIRST_ROW = 3;
const CONTENT_FIRST_ROW = 3;

// Inline skeleton components
const CategoryPillSkeleton: React.FC = () => (
    <div className="omniguide-skeleton__pill omniguide-skeleton">
        <span className="omniguide-skeleton__text" style={{ width: '120px' }} />
        <span className="omniguide-skeleton__text" style={{ width: '30px' }} />
    </div>
);

const ProductCardSkeleton: React.FC = () => (
    <div className="omniguide-skeleton__card omniguide-skeleton">
        <div className="omniguide-skeleton__image" />
        <div className="omniguide-skeleton__body">
            <div className="omniguide-skeleton__text omniguide-skeleton__text--brand" />
            <div className="omniguide-skeleton__text omniguide-skeleton__text--title" />
            <div className="omniguide-skeleton__text omniguide-skeleton__text--price" />
        </div>
    </div>
);

const ContentCardSkeleton: React.FC = () => (
    <div className="omniguide-skeleton__card omniguide-skeleton__card--blog omniguide-skeleton">
        <div className="omniguide-skeleton__image omniguide-skeleton__image--blog" />
        <div className="omniguide-skeleton__body">
            <div className="omniguide-skeleton__text omniguide-skeleton__text--blog-title" />
            <div className="omniguide-skeleton__text omniguide-skeleton__text--full" />
            <div className="omniguide-skeleton__text omniguide-skeleton__text--short" />
        </div>
    </div>
);

const SkeletonResults: React.FC = () => (
    <div style={{ display: 'flex', flexDirection: 'column', gap: '32px' }}>
        <div>
            <h3 className="omniguide-results__section-title">Categories</h3>
            <div className="omniguide-results__categories-grid">
                <CategoryPillSkeleton />
                <CategoryPillSkeleton />
                <CategoryPillSkeleton />
            </div>
        </div>
        <div>
            <h3 className="omniguide-results__section-title">Products</h3>
            <div className="omniguide-results__grid">
                <ProductCardSkeleton />
                <ProductCardSkeleton />
                <ProductCardSkeleton />
            </div>
        </div>
    </div>
);

interface CategoryData {
    data?: {
        id?: number | string;
        name?: string;
        path?: string;
        url?: string;
        product_count?: number;
    };
    name?: string;
}

interface CategoryPillsProps {
    categories: CategoryData[];
    onCategoryClick?: (data: Record<string, unknown>) => void;
    messageId?: string;
    queryContext?: string;
    aiSearchStoreUrl?: string;
}

const CategoryPills: React.FC<CategoryPillsProps> = ({ categories, onCategoryClick, messageId, queryContext, aiSearchStoreUrl }) => {
    const [showAll, setShowAll] = useState(false);
    const [hoveredIndex, setHoveredIndex] = useState<number | null>(null);
    const [seeMoreHovered, setSeeMoreHovered] = useState(false);

    if (!categories || categories.length === 0) return null;

    const hasMore = categories.length > CATEGORIES_FIRST_ROW;
    const visibleCategories = showAll ? categories : categories.slice(0, CATEGORIES_FIRST_ROW);
    const remainingCount = categories.length - CATEGORIES_FIRST_ROW;

    const handleCategoryClick = (event: React.MouseEvent, category: CategoryData, index: number) => {
        const data = category.data || category;
        const urlPath = (data as Record<string, unknown>)['path'] as string || (data as Record<string, unknown>)['url'] as string;

        if (!urlPath) return;

        const safeUrl = buildSafeUrl(aiSearchStoreUrl, urlPath);
        if (!safeUrl) return;

        if (onCategoryClick) {
            onCategoryClick({
                messageId,
                categoryId: (data as Record<string, unknown>)['id'],
                name: (data as Record<string, unknown>)['name'],
                url: safeUrl,
                position: index,
                queryContext,
            });
        }

        setTimeout(() => {
            safeNavigate(safeUrl, undefined, { event: event as unknown as { ctrlKey?: boolean; metaKey?: boolean } });
        }, 0);
    };

    return (
        <div className="omniguide-results__categories-grid">
            {visibleCategories.map((category, index) => {
                const name = category.data?.name || category.name;
                const productCount = category.data?.product_count;

                return (
                    <button
                        key={category.data?.id || index}
                        onClick={(event) => handleCategoryClick(event, category, index)}
                        className="omniguide-flex-align-center omniguide-category-pill-base omniguide-category-pill"
                        data-hovered={hoveredIndex === index}
                        onMouseEnter={() => setHoveredIndex(index)}
                        onMouseLeave={() => setHoveredIndex(null)}
                    >
                        <span style={{ flex: 1 }}>{name}</span>
                        {productCount !== undefined && productCount !== null && (
                            <span className="omniguide-category-pill__count">({productCount})</span>
                        )}
                    </button>
                );
            })}
            {hasMore && !showAll && (
                <button
                    onClick={() => setShowAll(true)}
                    className="omniguide-flex-center omniguide-category-pill-base omniguide-category-pill--see-more"
                    data-hovered={seeMoreHovered}
                    onMouseEnter={() => setSeeMoreHovered(true)}
                    onMouseLeave={() => setSeeMoreHovered(false)}
                >
                    See more ({remainingCount})
                </button>
            )}
        </div>
    );
};

const SeeMoreProductCard: React.FC<{ onClick: () => void; remainingCount: number }> = ({ onClick, remainingCount }) => {
    const [isHovered, setIsHovered] = useState(false);

    return (
        <button
            onClick={onClick}
            onMouseEnter={() => setIsHovered(true)}
            onMouseLeave={() => setIsHovered(false)}
            className="omniguide-flex-center omniguide-product-card--see-more"
            data-hovered={isHovered}
        >
            <span className="omniguide-product-card__see-more-text">See more</span>
            <span className="omniguide-product-card__see-more-count">+{remainingCount}</span>
        </button>
    );
};

const SeeMoreBlogCard: React.FC<{ onClick: () => void; remainingCount: number }> = ({ onClick, remainingCount }) => {
    const [isHovered, setIsHovered] = useState(false);

    return (
        <button
            onClick={onClick}
            onMouseEnter={() => setIsHovered(true)}
            onMouseLeave={() => setIsHovered(false)}
            className="omniguide-flex-center omniguide-blog-card--see-more"
            data-hovered={isHovered}
        >
            <span className="omniguide-blog-card__see-more-text">Show more</span>
            <span className="omniguide-blog-card__see-more-count">+{remainingCount}</span>
        </button>
    );
};

interface SourceItem {
    type: string;
    data?: Record<string, unknown>;
}

export interface SearchResultsPanelProps {
    sources?: SourceItem[];
    trackProductClick?: SearchProductCardProps['trackProductClick'];
    trackCategoryClick?: (data: Record<string, unknown>) => void;
    trackContentClick?: SearchBlogCardProps['trackContentClick'];
    messageId?: string;
    queryContext?: string;
    isLoading?: boolean;
    aiSearchStoreUrl?: string;
    fallbackProductImage?: string;
    fallbackBlogImage?: string;
    showProductTags?: boolean;
    /** How to display zero/null price: 'show' (default) | 'hide' | custom text */
    zeroPriceDisplay?: string;
}

export const SearchResultsPanel: React.FC<SearchResultsPanelProps> = ({
    sources = [],
    trackProductClick,
    trackCategoryClick,
    trackContentClick,
    messageId,
    queryContext,
    isLoading = false,
    aiSearchStoreUrl,
    fallbackProductImage,
    fallbackBlogImage,
    showProductTags,
    zeroPriceDisplay,
}) => {
    const SearchProductCard = useComponent('SearchProductCard', DefaultSearchProductCard);
    const SearchBlogCard = useComponent('SearchBlogCard', DefaultSearchBlogCard);

    const [showAllProducts, setShowAllProducts] = useState(false);
    const [showAllContent, setShowAllContent] = useState(false);

    const products = sources.filter(s => s.type === 'product' && s.data);
    const categories = sources.filter(s => s.type === 'category' && s.data);
    const content = sources.filter(s => s.type === 'content' && s.data);

    const hasResults = products.length > 0 || categories.length > 0 || content.length > 0;

    const hasMoreProducts = products.length > PRODUCTS_FIRST_ROW;
    const visibleProducts = showAllProducts ? products : products.slice(0, PRODUCTS_FIRST_ROW);
    const remainingProducts = products.length - PRODUCTS_FIRST_ROW;

    const hasMoreContent = content.length > CONTENT_FIRST_ROW;
    const visibleContent = showAllContent ? content : content.slice(0, CONTENT_FIRST_ROW);
    const remainingContent = content.length - CONTENT_FIRST_ROW;

    return (
        <div className="omniguide-results">
            <div className="omniguide-results__content">
                {isLoading ? (
                    <SkeletonResults />
                ) : !hasResults ? (
                    <div className="omniguide-results__empty-state">
                        <p>Results will appear here as you search</p>
                    </div>
                ) : (
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '32px' }}>
                        {categories.length > 0 && (
                            <div>
                                <h3 className="omniguide-results__section-title">Categories</h3>
                                <CategoryPills
                                    categories={categories as CategoryData[]}
                                    onCategoryClick={trackCategoryClick}
                                    messageId={messageId}
                                    queryContext={queryContext}
                                    aiSearchStoreUrl={aiSearchStoreUrl}
                                />
                            </div>
                        )}

                        {products.length > 0 && (
                            <div>
                                <h3 className="omniguide-results__section-title">Products</h3>
                                <div className="omniguide-results__grid">
                                    {visibleProducts.map((source, index) => (
                                        <SearchProductCard
                                            key={(source.data as Record<string, unknown>)?.['entityId'] as string || (source.data as Record<string, unknown>)?.['id'] as string || index}
                                            product={source.data as SearchProductCardProps['product']}
                                            index={index}
                                            messageId={messageId}
                                            queryContext={queryContext}
                                            trackProductClick={trackProductClick}
                                            aiSearchStoreUrl={aiSearchStoreUrl}
                                            fallbackImage={fallbackProductImage}
                                            showProductTags={showProductTags}
                                            zeroPriceDisplay={zeroPriceDisplay}
                                        />
                                    ))}
                                    {hasMoreProducts && !showAllProducts && (
                                        <SeeMoreProductCard
                                            onClick={() => setShowAllProducts(true)}
                                            remainingCount={remainingProducts}
                                        />
                                    )}
                                </div>
                            </div>
                        )}

                        {content.length > 0 && (
                            <div>
                                <h3 className="omniguide-results__section-title">Related Content</h3>
                                <div className="omniguide-results__content-grid">
                                    {visibleContent.map((source, index) => (
                                        <SearchBlogCard
                                            key={(source.data as Record<string, unknown>)?.['id'] as string || index}
                                            source={source as SearchBlogCardProps['source']}
                                            index={index}
                                            messageId={messageId}
                                            queryContext={queryContext}
                                            trackContentClick={trackContentClick}
                                            fallbackImage={fallbackBlogImage}
                                        />
                                    ))}
                                    {hasMoreContent && !showAllContent && (
                                        <SeeMoreBlogCard
                                            onClick={() => setShowAllContent(true)}
                                            remainingCount={remainingContent}
                                        />
                                    )}
                                </div>
                            </div>
                        )}
                    </div>
                )}
            </div>
        </div>
    );
};
