/**
 * Fetch real product URLs from a BigCommerce backend by SKUs.
 * Used by the search chat to resolve product links in streamed markdown.
 */

import { createScopedLogger } from '@swiftotter/omniguide-core';

const log = createScopedLogger('productUrls');

export interface ProductUrlsConfig {
    apiBaseUrl: string;
    websiteId: string;
    getGraphQLToken?: () => string | null;
}

export async function fetchProductUrlsBySkus(
    skus: string[],
    config: ProductUrlsConfig,
): Promise<Record<string, string>> {
    if (!skus || skus.length === 0) return {};

    const graphqlToken = config.getGraphQLToken?.() ?? null;

    try {
        const headers: Record<string, string> = {
            'Content-Type': 'application/json',
        };

        if (graphqlToken) {
            headers['X-Storefront-Token'] = graphqlToken;
        }

        const response = await fetch(
            `${config.apiBaseUrl}/api/v1/bc-search-products`,
            {
                method: 'POST',
                headers,
                body: JSON.stringify({
                    skus,
                    website_code: config.websiteId,
                    graphql_token: graphqlToken,
                }),
            },
        );

        if (!response.ok) {
            log.warn('Failed to fetch product URLs: HTTP', response.status);
            return {};
        }

        const data = await response.json();
        const products: Array<Record<string, unknown>> = data?.products ?? [];

        const urlMap: Record<string, string> = {};
        products.forEach((product) => {
            const productUrl =
                (product['url'] as string) ??
                (product['path'] as string) ??
                (product['custom_url'] as Record<string, string> | undefined)?.['url'];

            if (product['sku'] && productUrl) {
                urlMap[String(product['sku'])] = productUrl;
            }
        });

        const missingSkus = skus.filter((sku) => !urlMap[String(sku)]);
        if (missingSkus.length > 0) {
            log.warn('Product URLs not found for SKUs:', missingSkus);
        }

        return urlMap;
    } catch (error) {
        log.warn('Failed to fetch product URLs:', error);
        return {};
    }
}
