import React, { useMemo, useRef, useState, useEffect } from 'react';
import { SearchProductCard as DefaultSearchProductCard } from './SearchProductCard.js';
import type { SearchProductCardProps } from './SearchProductCard.js';
import { SearchCategoryCard as DefaultSearchCategoryCard } from './SearchCategoryCard.js';
import type { SearchCategoryCardProps } from './SearchCategoryCard.js';
import { SearchBlogCard as DefaultSearchBlogCard } from './SearchBlogCard.js';
import type { SearchBlogCardProps } from './SearchBlogCard.js';
import { useComponent } from '../../hooks/useComponent.js';

const MobileProductSkeleton: React.FC = () => (
    <div className="omniguide-skeleton__card omniguide-skeleton">
        <div className="omniguide-skeleton__image" />
        <div className="omniguide-skeleton__body">
            <div className="omniguide-skeleton__text omniguide-skeleton__text--brand" />
            <div className="omniguide-skeleton__text omniguide-skeleton__text--title" />
            <div className="omniguide-skeleton__text omniguide-skeleton__text--price" />
        </div>
    </div>
);

const LoadingOverlay: React.FC = () => (
    <div className="omniguide-mobile-results__loading-overlay">
        <div className="omniguide-mobile-results__loading-spinner">
            <svg width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                <circle cx="12" cy="12" r="10" strokeOpacity="0.25" />
                <path d="M12 2a10 10 0 0 1 10 10" strokeLinecap="round">
                    <animateTransform
                        attributeName="transform"
                        type="rotate"
                        from="0 12 12"
                        to="360 12 12"
                        dur="1s"
                        repeatCount="indefinite"
                    />
                </path>
            </svg>
            <span>Loading recommendations...</span>
        </div>
    </div>
);

interface MessageLike {
    id: string;
    role: string;
    content?: string;
    sources?: unknown[];
    queryContext?: string;
}

export interface SearchMobileResultsPanelProps {
    messages: MessageLike[];
    trackProductClick?: SearchProductCardProps['trackProductClick'];
    trackCategoryClick?: SearchCategoryCardProps['trackCategoryClick'];
    trackContentClick?: SearchBlogCardProps['trackContentClick'];
    currentSectionIndex?: number;
    isLoading?: boolean;
    currentQuestion?: string;
    isBottomSheetExpanded?: boolean;
    aiSearchStoreUrl?: string;
    fallbackProductImage?: string;
    fallbackCategoryImage?: string;
    fallbackBlogImage?: string;
    showProductTags?: boolean;
    /** How to display zero/null price: 'show' (default) | 'hide' | custom text */
    zeroPriceDisplay?: string;
}

export const SearchMobileResultsPanel: React.FC<SearchMobileResultsPanelProps> = ({
    messages,
    trackProductClick,
    trackCategoryClick,
    trackContentClick,
    currentSectionIndex = 0,
    isLoading = false,
    currentQuestion = '',
    isBottomSheetExpanded = false,
    aiSearchStoreUrl,
    fallbackProductImage,
    fallbackCategoryImage,
    fallbackBlogImage,
    showProductTags,
    zeroPriceDisplay,
}) => {
    const SearchProductCard = useComponent('SearchProductCard', DefaultSearchProductCard);
    const SearchCategoryCard = useComponent('SearchCategoryCard', DefaultSearchCategoryCard);
    const SearchBlogCard = useComponent('SearchBlogCard', DefaultSearchBlogCard);

    const emptyStateRef = useRef<HTMLDivElement>(null);
    const [adjustedMargin, setAdjustedMargin] = useState<number | null>(null);

    useEffect(() => {
        if (!emptyStateRef.current) {
            setAdjustedMargin(null);
            return;
        }

        const checkOverlap = () => {
            const emptyStateEl = emptyStateRef.current;
            const bottomSheet = document.querySelector('.omniguide-mobile-bottom-sheet');

            if (!emptyStateEl || !bottomSheet) {
                setAdjustedMargin(null);
                return;
            }

            const textEl = emptyStateEl.lastElementChild || emptyStateEl;
            const textRect = textEl.getBoundingClientRect();
            const bottomSheetRect = bottomSheet.getBoundingClientRect();
            const spacing = 18;

            if (bottomSheetRect.top < textRect.bottom + spacing) {
                const overlap = textRect.bottom + spacing - bottomSheetRect.top;
                const currentMargin = 80;
                const newMargin = Math.max(16, currentMargin - overlap);
                setAdjustedMargin(newMargin);
            } else {
                setAdjustedMargin(null);
            }
        };

        checkOverlap();

        window.addEventListener('resize', checkOverlap);
        return () => window.removeEventListener('resize', checkOverlap);
    }, [isBottomSheetExpanded, messages.length]);

    const sections = useMemo(() => {
        const result: Array<{
            id: string;
            question: string;
            sources: Array<{ type: string; data?: Record<string, unknown> }>;
            messageId: string;
            queryContext?: string;
        }> = [];
        const chronologicalMessages = [...messages].reverse();

        for (let i = 0; i < chronologicalMessages.length; i++) {
            const message = chronologicalMessages[i]!;

            if (message.role === 'user') {
                const nextMessage = chronologicalMessages[i + 1];
                if (nextMessage && nextMessage.role === 'assistant' && nextMessage.sources && nextMessage.sources.length > 0) {
                    result.push({
                        id: message.id,
                        question: message.content || '',
                        sources: nextMessage.sources as Array<{ type: string; data?: Record<string, unknown> }>,
                        messageId: nextMessage.id,
                        queryContext: nextMessage.queryContext,
                    });
                }
            }
        }
        return result;
    }, [messages]);

    if (isLoading && sections.length === 0) {
        return (
            <div className="omniguide-mobile-results">
                {currentQuestion && (
                    <div className="omniguide-mobile-results__section-header">
                        <h3 className="omniguide-mobile-results__section-question">{currentQuestion}</h3>
                    </div>
                )}
                <div className="omniguide-mobile-results__grid">
                    <MobileProductSkeleton />
                    <MobileProductSkeleton />
                    <MobileProductSkeleton />
                    <MobileProductSkeleton />
                </div>
            </div>
        );
    }

    if (sections.length === 0) {
        return (
            <div
                ref={emptyStateRef}
                className="omniguide-results__empty-state"
                style={{
                    height: '100%',
                    padding: '32px',
                    ...(adjustedMargin !== null && { marginTop: `${adjustedMargin}px` }),
                }}
            >
                <p>Ask a question to see product recommendations</p>
            </div>
        );
    }

    const section = sections[currentSectionIndex];
    if (!section) {
        return (
            <div className="omniguide-results__empty-state" style={{ height: '100%', padding: '32px' }}>
                <p>Ask a question to see product recommendations</p>
            </div>
        );
    }

    const products = section.sources.filter(s => s.type === 'product' && s.data);
    const categories = section.sources.filter(s => s.type === 'category' && s.data);
    const content = section.sources.filter(s => s.type === 'content' && s.data);

    const displayQuestion = isLoading && currentQuestion ? currentQuestion : section.question;

    return (
        <div className="omniguide-mobile-results">
            {isLoading && <LoadingOverlay />}

            <div key={section.id} id={`section-${section.id}`} className={isLoading ? 'omniguide-mobile-results__content--loading' : ''}>
                <div className="omniguide-mobile-results__section-header">
                    <h3 className="omniguide-mobile-results__section-question">{displayQuestion}</h3>
                </div>

                {products.length > 0 && (
                    <div className="omniguide-mobile-results__grid">
                        {products.map((source, index) => (
                            <SearchProductCard
                                key={(source.data as Record<string, unknown>)?.['entityId'] as string || (source.data as Record<string, unknown>)?.['id'] as string || index}
                                product={source.data as SearchProductCardProps['product']}
                                index={index}
                                messageId={section.messageId}
                                queryContext={section.queryContext}
                                trackProductClick={trackProductClick}
                                aiSearchStoreUrl={aiSearchStoreUrl}
                                fallbackImage={fallbackProductImage}
                                showProductTags={showProductTags}
                                zeroPriceDisplay={zeroPriceDisplay}
                            />
                        ))}
                    </div>
                )}

                {categories.length > 0 && (
                    <div style={{
                        display: 'flex',
                        gap: '8px',
                        padding: '0 16px 16px 16px',
                        overflowX: 'auto',
                    }}>
                        {categories.map((source, index) => (
                            <div key={(source.data as Record<string, unknown>)?.['id'] as string || index} style={{ flex: '0 0 auto' }}>
                                <SearchCategoryCard
                                    source={source as SearchCategoryCardProps['source']}
                                    index={index}
                                    messageId={section.messageId}
                                    queryContext={section.queryContext}
                                    trackCategoryClick={trackCategoryClick}
                                    aiSearchStoreUrl={aiSearchStoreUrl}
                                    fallbackImage={fallbackCategoryImage}
                                />
                            </div>
                        ))}
                    </div>
                )}

                {content.length > 0 && (
                    <div className="omniguide-mobile-results__grid">
                        {content.map((source, index) => (
                            <SearchBlogCard
                                key={(source.data as Record<string, unknown>)?.['id'] as string || index}
                                source={source as SearchBlogCardProps['source']}
                                index={index}
                                messageId={section.messageId}
                                queryContext={section.queryContext}
                                trackContentClick={trackContentClick}
                                fallbackImage={fallbackBlogImage}
                            />
                        ))}
                    </div>
                )}
            </div>
        </div>
    );
};
