import React, { memo, useState } from 'react';
import { transformSummary } from '@swiftotter/omniguide-core';
import { decodeHtmlEntities, isValidNavigationUrl, safeNavigate } from '../../utils/index.js';

export interface SearchBlogData {
    id?: number | string;
    name?: string;
    title?: string;
    url?: string;
    summary?: string;
    image?: { url?: string; altText?: string };
}

export interface SearchBlogCardProps {
    source: { data?: SearchBlogData } | null;
    index: number;
    messageId?: string;
    queryContext?: string;
    trackContentClick?: (data: Record<string, unknown>) => void;
    fallbackImage?: string;
}

export const SearchBlogCard: React.FC<SearchBlogCardProps> = memo(({
    source,
    index,
    messageId,
    queryContext,
    trackContentClick,
    fallbackImage,
}) => {
    const [isHovered, setIsHovered] = useState(false);

    if (!source?.data) return null;

    const { data } = source;

    const handleClick = (event: React.MouseEvent | React.KeyboardEvent) => {
        const baseUrl = data.url || '';

        if (!isValidNavigationUrl(baseUrl)) return;

        let fullUrl: string;
        try {
            const url = new URL(baseUrl, window.location.origin);
            fullUrl = url.href;
        } catch {
            return;
        }

        if (trackContentClick) {
            trackContentClick({
                messageId,
                contentId: data.id,
                title: data.name || data.title,
                url: fullUrl,
                position: index,
                queryContext,
            });
        }

        setTimeout(() => {
            safeNavigate(fullUrl, undefined, { event: event as unknown as { ctrlKey?: boolean; metaKey?: boolean } });
        }, 30);
    };

    const imageSrc = data?.image?.url || fallbackImage || '';
    const imageAlt = decodeHtmlEntities(data?.image?.altText || data.name || '');
    const title = decodeHtmlEntities(data.name || '');

    const handleKeyDown = (e: React.KeyboardEvent) => {
        if (e.key === 'Enter' || e.key === ' ') {
            e.preventDefault();
            handleClick(e);
        }
    };

    return (
        <div
            className="omniguide-blog-card"
            data-hovered={isHovered}
            onMouseEnter={() => setIsHovered(true)}
            onMouseLeave={() => setIsHovered(false)}
            onClick={handleClick}
            onKeyDown={handleKeyDown}
            tabIndex={0}
            role="link"
            aria-label={`Read article: ${title}`}
        >
            {imageSrc && (
                <div className="omniguide-blog-card__image-wrapper">
                    <img
                        src={imageSrc}
                        alt={imageAlt}
                        className="omniguide-blog-card__image"
                    />
                </div>
            )}
            <div className="omniguide-blog-card__body">
                <h4 className="omniguide-blog-card__title">
                    {decodeHtmlEntities(data.name || '')}
                </h4>
                {data.summary && (
                    <p className="omniguide-blog-card__summary">
                        {transformSummary(data.summary)}
                    </p>
                )}
            </div>
        </div>
    );
});

SearchBlogCard.displayName = 'SearchBlogCard';
