/**
 * useSessionInit — Session initialization hook for BigCommerce themes.
 *
 * Ported from theme `search/hooks/useSession.js`.
 * Uses DI callbacks from OmniguideConfig instead of importing PostHog directly.
 * Creates ConsentService internally from config.
 */

import { useState, useEffect, useCallback } from 'react';
import { useOmniguideContext } from '@swiftotter/omniguide-react';
import { API_ENDPOINTS, createScopedLogger, setRegistrySessionId, getRegistrySessionId, normalizeSessionResponse, RestSessionResponseSchema, setFeatureStatus, getCurrentPage } from '@swiftotter/omniguide-core';

const log = createScopedLogger('useSessionInit');

// ── Types ──────────────────────────────────────────────────────────

export interface UseSessionInitReturn {
  sessionId: string | null;
  setSessionId: (id: string | null) => void;
  welcomeText: string;
  seedQuestions: string[];
  aiDisabled: boolean;
  disabledReason: string | null;
  isInitialized: boolean;
}

// ── Hook ───────────────────────────────────────────────────────────

export function useSessionInit(): UseSessionInitReturn {
  const { config, consentService } = useOmniguideContext();
  const { apiBaseUrl, websiteId, callbacks, storageKeys } = config;

  const sessionStorageKey = storageKeys?.sessionId ?? 'aiSearchSessionId';

  const [sessionId, setSessionId] = useState<string | null>(() => {
    try {
      return localStorage.getItem(sessionStorageKey) ?? null;
    } catch {
      return null;
    }
  });
  const [welcomeText, setWelcomeText] = useState('');
  const [seedQuestions, setSeedQuestions] = useState<string[]>([]);
  const [aiDisabled, setAiDisabled] = useState(false);
  const [disabledReason, setDisabledReason] = useState<string | null>(null);
  const [isInitialized, setIsInitialized] = useState(false);

  // Initialize session on mount
  useEffect(() => {
    const initializeSession = async () => {
      // Wait for feature flags to load (DI callback)
      if (callbacks?.waitForFeatureFlags) {
        await callbacks.waitForFeatureFlags();
      }

      // Check if feature is enabled (DI callback)
      if (callbacks?.isFeatureEnabled && !callbacks.isFeatureEnabled()) {
        setIsInitialized(true);
        return;
      }

      try {
        const currentSessionId =
          localStorage.getItem(sessionStorageKey) ?? undefined;

        const url = `${apiBaseUrl}${API_ENDPOINTS.CONVERSATIONAL_SEARCH_INIT}`;

        const response = await fetch(url, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            website_code: websiteId,
            session_id: currentSessionId,
            current_page: getCurrentPage(),
          }),
        });

        if (response.ok) {
          const raw = await response.json();
          const normalized = normalizeSessionResponse(raw);
          const validated = RestSessionResponseSchema.safeParse(normalized);

          if (validated.success) {
            const data = validated.data;

            if (data.sessionId) {
              localStorage.setItem(sessionStorageKey, data.sessionId);
              setRegistrySessionId(websiteId, data.sessionId);
              setSessionId(data.sessionId);
            }

            if (data.welcomeText) {
              setWelcomeText(data.welcomeText);
            }
            if (data.seedQuestions && Array.isArray(data.seedQuestions)) {
              setSeedQuestions(data.seedQuestions);
            }
            if (typeof data.aiDisabled === 'boolean') {
              setAiDisabled(data.aiDisabled);
            }
            if (data.disabledReason) {
              setDisabledReason(data.disabledReason);
            }

            // Publish feature status to registry for cross-tree consumers (PDP/PLP widgets)
            setFeatureStatus(websiteId, {
              aiDisabled: data.aiDisabled ?? false,
            });
          }
        }
      } catch (error) {
        log.error('Failed to initialize session:', error);
        // Don't block widgets on init failure
        setFeatureStatus(websiteId, { aiDisabled: false });
      } finally {
        setIsInitialized(true);
      }
    };

    initializeSession();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Sync session ID to registry
  useEffect(() => {
    if (sessionId) {
      setRegistrySessionId(websiteId, sessionId);
    }
  }, [sessionId, websiteId]);

  // Initialize consent when session is available
  useEffect(() => {
    if (!sessionId || !consentService) return;

    (async () => {
      await consentService.ensureInitialized(sessionId);
      consentService.startWatcher(sessionId);
    })();

    return () => {
      consentService.stopWatcher();
    };
  }, [sessionId, consentService]);

  return {
    sessionId,
    setSessionId,
    welcomeText,
    seedQuestions,
    aiDisabled,
    disabledReason,
    isInitialized,
  };
}
