import { useEffect } from 'react';
import type { RefObject } from 'react';

/**
 * Hook to trap focus within a modal/overlay for accessibility
 * @param isActive - Whether the focus trap is active
 * @param containerRef - Ref to the container element
 * @param preferredSelector - CSS selector for preferred initial focus target
 */
export const useFocusTrap = (
    isActive: boolean,
    containerRef: RefObject<HTMLElement>,
    preferredSelector: string | null = null
): void => {
    useEffect(() => {
        if (!isActive) return;

        const focusableSelectors = [
            'button:not([disabled])',
            'input:not([disabled])',
            'textarea:not([disabled])',
            'select:not([disabled])',
            'a[href]',
            '[tabindex]:not([tabindex="-1"])',
        ].join(', ');

        const getFocusableElements = (): HTMLElement[] => {
            if (!containerRef.current) return [];
            const focusableElements = containerRef.current.querySelectorAll(focusableSelectors);
            return Array.from(focusableElements).filter(
                (el) => (el as HTMLElement).offsetParent !== null
            ) as HTMLElement[];
        };

        const getFirstFocusTarget = (): HTMLElement | null => {
            if (!containerRef.current) return null;
            if (preferredSelector) {
                const preferred = containerRef.current.querySelector(preferredSelector) as HTMLElement;
                if (preferred) return preferred;
            }
            const focusableArray = getFocusableElements();
            return focusableArray[0] || null;
        };

        const handleKeyDown = (e: KeyboardEvent): void => {
            if (e.key !== 'Tab' || !containerRef.current) return;

            const focusableArray = getFocusableElements();
            if (focusableArray.length === 0) return;

            const firstElement = focusableArray[0];
            const lastElement = focusableArray[focusableArray.length - 1];

            const isFocusInContainer = containerRef.current.contains(document.activeElement);

            if (!isFocusInContainer) {
                e.preventDefault();
                const target = getFirstFocusTarget();
                if (target) target.focus();
                return;
            }

            if (e.shiftKey) {
                if (document.activeElement === firstElement && lastElement) {
                    e.preventDefault();
                    lastElement.focus();
                }
            } else {
                if (document.activeElement === lastElement && firstElement) {
                    e.preventDefault();
                    firstElement.focus();
                }
            }
        };

        document.addEventListener('keydown', handleKeyDown);

        return () => {
            document.removeEventListener('keydown', handleKeyDown);
        };
    }, [isActive, containerRef, preferredSelector]);
};

export default useFocusTrap;
