/**
 * Security utilities for URL validation and safe navigation.
 * DOM-dependent — uses `window.location`, `window.open`.
 */

export interface NavigateOptions {
    /** Force open in new tab */
    newTab?: boolean;
    /** Click event (to detect CTRL/CMD modifier) */
    event?: { ctrlKey?: boolean; metaKey?: boolean };
}

/**
 * Validates that a URL is safe for navigation (no javascript:, data:, vbscript: protocols).
 */
export function isValidNavigationUrl(url: string, baseUrl = window.location.origin): boolean {
    if (!url || typeof url !== 'string') {
        return false;
    }

    try {
        const fullUrl = url.startsWith('http://') || url.startsWith('https://')
            ? url
            : new URL(url, baseUrl).href;

        const parsed = new URL(fullUrl);

        const allowedProtocols = ['http:', 'https:'];
        if (!allowedProtocols.includes(parsed.protocol)) {
            return false;
        }

        return true;
    } catch {
        return false;
    }
}

/**
 * Safely navigate to a URL after validation.
 * @returns true if navigation was attempted, false if blocked.
 */
export function safeNavigate(url: string, baseUrl = window.location.origin, options: NavigateOptions = {}): boolean {
    if (!isValidNavigationUrl(url, baseUrl)) {
        return false;
    }

    const { newTab = false, event } = options;
    const openInNewTab = newTab || event?.ctrlKey || event?.metaKey;

    if (openInNewTab) {
        window.open(url, '_blank', 'noopener,noreferrer');
    } else {
        window.location.href = url;
    }
    return true;
}

/**
 * Build a safe URL with query parameters.
 * @returns The constructed URL or null if invalid.
 */
export function buildSafeUrl(baseUrl: string | undefined, path: string, params: Record<string, string> = {}): string | null {
    try {
        if (path && (path.startsWith('javascript:') || path.startsWith('data:') || path.startsWith('vbscript:'))) {
            return null;
        }

        const resolvedBase = (baseUrl || window.location.origin).replace(/\/+$/, '');

        // If path is already a full URL, use it directly; otherwise resolve against baseUrl
        const url = (path && (path.startsWith('http://') || path.startsWith('https://')))
            ? new URL(path)
            : new URL(path || '', resolvedBase);

        Object.entries(params).forEach(([key, value]) => {
            if (value !== undefined && value !== null) {
                url.searchParams.set(key, String(value));
            }
        });

        if (!isValidNavigationUrl(url.href)) {
            return null;
        }

        return url.href;
    } catch {
        return null;
    }
}
